# 2. Discord настройки
intents = discord.Intents.default()
intents.message_content = True

bot = commands.Bot(command_prefix="!", intents=intents)

@bot.event
async def on_ready():
    print(f"Бот {bot.user} запущен!")

@bot.event
async def on_message(message):
    if message.author == bot.user:
        return

    if bot.user.mentioned_in(message):
        # Убираем оба варианта упоминания
        user_text = message.content.replace(f"<@{bot.user.id}>", "") \
                                   .replace(f"<@!{bot.user.id}>", "") \
                                   .strip()

        if not user_text:
            await message.channel.send("Ну и чего ты молчишь? Спроси что-нибудь!")
            return

        async with message.channel.typing():
            try:
                response = client.chat.completions.create(
                    model="deepseek-chat",
                    messages=[
                        {"role": "system", "content": SYSTEM_PROMPT},
                        {"role": "user", "content": user_text}
                    ],
                    max_tokens=300
                )

                bot_reply = response.choices[0].message.content
                await message.reply(bot_reply)

            except Exception as e:
                print(f"Ошибка API: {e}")
                await message.reply("Ой, у меня шестеренки заклинило. Попробуй позже.")

    await bot.process_commands(message)

# 3. Токен из env
DISCORD_BOT_TOKEN = os.getenv("DISCORD_BOT_TOKEN", "").strip()
if not DISCORD_BOT_TOKEN:
    raise RuntimeError("DISCORD_BOT_TOKEN is required")

bot.run(DISCORD_BOT_TOKEN)
